/// (/admin/entity-completeness).
///
/// Written for the salesperson and sales manager who score leads against an
/// Ideal Customer Profile: where leads come from and which channels pay off,
/// how a lead earns a high or low fit score, why the best-fit leads rise to the
/// top of the work list, and what information a customer or vendor record still
/// needs before the team can act on it.
/// </summary>
public class LeadScoringTraining : TrainingContentBase
{
    public LeadScoringTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Lead Sources & Quality Scores (Article) ──────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Lead Sources & Quality Scores",
            Slug = "lead-sources-overview",
            Summary = "Manage the Lead Sources catalog: a Name plus an immutable Code, the nightly auto-computed Quality Score, and why you deactivate a source instead of deleting it once leads are attributed to it.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/admin/lead-sources"]""",
            Tags = """["lead-scoring","lead-sources","admin","leads"]""",
            ContentJson = """{"body":"## Lead Sources & Quality Scores\n\nThe **Lead Sources** catalog (Admin → Lead Sources) is the authoritative list of where your leads come from — trade shows, a purchased list, the website contact form, a referral partner, a specific ad campaign. Every lead can be attributed to a source, and bulk-intake stamps that attribution automatically. Cataloging your sources lets you measure which channels actually produce business and which deliver garbage.\n\n### Name vs Code — and why Code is immutable\n\nA lead source has two identifiers:\n\n- **Name** — the human-readable label (e.g., 'IMTS 2026 Trade Show', 'Website Contact Form'). Fully editable; rename it whenever you like.\n- **Code** — a short, stable identifier (e.g., `imts-2026`, `web-contact`). The Code is set once when you create the source and **can never be changed afterward**. In the edit dialog the Code field is disabled.\n\nThe Code is the natural key that the rest of the system binds to: bulk-import pipelines map a column to a source Code, web forms and referrer URLs carry the Code, and historical leads point at it. If the Code could change, every one of those bindings would silently break. So choose it carefully at create time. The Code accepts letters, digits, hyphens, and underscores only.\n\n### The Quality Score\n\nEvery source carries a **Quality Score** from 0 to 100. This is **not** something you type in — it is computed automatically by a nightly background job from the *outcomes* of that source's leads. You cannot edit it; the column is read-only on this screen.\n\nThe score is a rolling measure of how good a source's leads turn out to be:\n\n- Every source starts at a neutral **50**.\n- Leads that **convert** to customers pull the score **up** (the strongest positive signal).\n- Leads that **engage** (a real two-way conversation) pull it **up** modestly.\n- Leads marked **Bad Data** or **Suppressed** (do-not-contact) pull it **down**.\n- Leads marked **Lost** pull it **down** modestly.\n- Only leads from roughly the **last 180 days** count — that window is what makes the score *rolling*, so a source that improved (or degraded) recently is reflected, not its all-time history.\n\nThe final number is clamped to 0–100. In the table the score is color-coded: green at 70+ (a strong source), amber from 40–69 (mixed), red below 40 (this channel is delivering leads that don't pan out — investigate the list provider or campaign).\n\nBecause the job runs nightly, the score lags real-time. A brand-new source sits at 50 until its leads accumulate outcomes and the next run picks them up.\n\n### Creating and editing a source\n\nClick **New Source** in the toolbar. Provide a **Name** and a **Code** (both required), and optionally a **Description** explaining what the source is. Save. When you edit an existing source you can change the Name, Description, and the **Active** toggle — but not the Code.\n\n### Deactivate vs Delete\n\nThere are two ways to retire a source, and they are not interchangeable:\n\n- **Deactivate** (set the Active toggle off) — the source stays in the system and stays attached to all its historical leads, but it no longer appears as a choice for new intake. Use this whenever a source has *any* leads attributed to it. Historical attribution survives, so your reporting and the source's Quality Score stay intact.\n- **Delete** (the trash icon) — permanently removes the source. The server **blocks the delete** with an error if any leads are linked to it. This is a guard rail: you can only hard-delete a source that was created by mistake and never used. If leads exist, the system tells you to deactivate instead.\n\nThe practical rule: **if a source has ever been used, deactivate it; only delete the truly-empty mistakes.**\n\n### How this feeds the rest of the system\n\nThe source on a lead is one of the fields the ICP scoring job can match against (see *ICP Rubrics & Weighted Dimensions*), and the per-source Quality Score helps you decide where to spend your lead-generation budget. Sources, rubrics, and completeness rules together make up the lead-scoring admin area.","sections":[]}"""
        });

        // ── ICP Rubrics & Weighted Dimensions (Article) ──────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "ICP Rubrics & Weighted Dimensions",
            Slug = "icp-rubrics-overview",
            Summary = "Build an Ideal Customer Profile rubric out of weighted dimensions, understand why only one rubric is the active scorer at a time, and follow the path from rubric, to each lead's nightly fit score, to the order of the sales work list.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/admin/icp-rubrics"]""",
            Tags = """["lead-scoring","icp","rubrics","admin","leads"]""",
            ContentJson = """{"body":"## ICP Rubrics & Weighted Dimensions\n\nAn **ICP rubric** (Ideal Customer Profile) is a scoring sheet that grades how well a lead fits the kind of customer you actually want. Admin → ICP Rubrics is where you build and tune those rubrics. The output is a 0–100 **fit score** stamped on every active lead, which the rep work-queue uses to surface the best-fit leads first.\n\n### The end-to-end picture (read this first)\n\nIt's worth understanding the whole chain before touching the editor:\n\n1. You define a **rubric** made of weighted **dimensions** (industry, company size, location, etc.).\n2. One rubric is flagged **Default** (and **Active**).\n3. A **nightly job** checks the default rubric's dimensions against every active lead, adds up the weights of the ones that match, scales the total to 0–100, and saves it as the lead's fit score.\n4. The **lead work-queue** orders leads by that score, so reps spend their time on the highest-fit prospects.\n\nNothing scores in real time — the score you see on a lead is the cached result of the last nightly run. Edit a rubric today, and the new weights take effect on the next run.\n\n### Rubric header fields\n\nClick **New Rubric** (or a row to edit). A rubric has:\n\n- **Name** (required) — e.g., 'Aerospace Machining ICP'.\n- **Description** — free-text reminder of who this rubric targets.\n- **Active** — whether the rubric is in play at all.\n- **Default** — whether this is *the* rubric the nightly scoring job uses.\n\n### The single-default invariant\n\nThe scoring job uses exactly one rubric: the one that is both **Active** and **Default**. The server enforces that **at most one rubric is the default** — when you mark a rubric as Default, the previously-default rubric is automatically un-defaulted in the same save. You never have to hunt down the old default and turn it off; flipping the flag on a new rubric is enough.\n\nA consequence worth internalizing: if **no** rubric is Active+Default, or the default rubric has **no dimensions**, or all its dimensions have **zero/negative** weight, the nightly job logs that it skipped and **no scores are written**. A rubric with dimensions but no positive weight can't produce a meaningful 0–100 score.\n\n### Dimensions — the criteria you score against\n\nInside the rubric editor is a **Dimensions** section. Each dimension is one thing you care about in a good customer — their industry, their size, where they're located, how they found you. Add as many as you need with **Add Dimension**; each row has four fields:\n\n- **What it looks at** (required) — which fact about the lead or its company this row checks: the industry, the headcount, the state, the company name, or the source the lead came from.\n- **Label** — a plain reminder of what the row is for ('Target aerospace & defense').\n- **Match rule** — what actually counts as a fit for this row: the industries, states, size range, or keywords you want to reward. *Setting Up ICP Match Rules* walks through each kind.\n- **Weight** (required) — how many points this row is worth when a lead fits. **Positive** weights reward a good fit; **negative** weights penalize a poor fit (e.g., −10 for an industry you don't serve).\n\n### How the score is computed\n\nFor each lead, the scoring looks at every dimension, and for the ones the lead fits, it adds that row's weight. The running total is divided by the **sum of all the positive weights** (the best a lead could possibly score), multiplied by 100, and kept within 0–100. So:\n\n- A lead that fits your highest-weighted dimensions lands near 100.\n- A lead that fits nothing (or trips a negative-weight penalty) lands near 0.\n- The *relative* weights are what matter — doubling every weight changes nothing, because the top of the scale doubles too. A dimension worth twice as much as another is what moves the needle.\n\n### Saving\n\nThe editor saves the rubric's basics and its dimensions together in one action. Deleting a dimension row and saving removes it. Because you usually tune several rows at once, one save records the whole change as a single activity entry rather than one per row.\n\n### Where to go next\n\nThe match rule is the one part of a dimension worth a closer look. *Setting Up ICP Match Rules* walks through each kind of rule — industries, states, size ranges, and keyword lists — and when to reach for each.","sections":[]}"""
        });

        // ── Setting Up ICP Match Rules (Walkthrough) ─────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Setting Up ICP Match Rules",
            Slug = "icp-match-specs-walkthrough",
            Summary = "A guided tour of the ICP Rubrics page that shows how to set the match rule on each dimension — keyword lists, target industries and states, and a company-size range — and how a lead is graded against them each night.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/admin/icp-rubrics"]""",
            Tags = """["lead-scoring","icp","match-rule","walkthrough","sales"]""",
            ContentJson = """{"appRoute":"/admin/icp-rubrics","startButtonLabel":"Tour ICP Rubrics","steps":[{"element":".toolbar__hint","popover":{"title":"ICP Rubrics","description":"This page lists every ideal-customer-profile rubric. Each night, the one rubric marked both Active and Default grades every active lead from 0 to 100 on how well it fits the kind of customer you want. That score is what puts the best-fit leads at the top of a rep's work list.","side":"bottom"}},{"element":"[data-testid='icp-rubric-new-btn']","popover":{"title":"New Rubric","description":"Click here to create a rubric, or click a row to edit one. The editor holds the rubric's basics (Name, Description, Active, Default) and its scoring rows together, and saves them all at once.","side":"left"}},{"element":"app-data-table","popover":{"title":"The rubric list","description":"Each row shows the rubric's name, how many scoring rows it has, and labels for Default and Active. Only one rubric can be the Default — pick a new one and the old one is unmarked for you. The row count tells you at a glance whether a rubric can actually score anything.","side":"top"}},{"element":"app-data-table","popover":{"title":"Dimensions and their match rules","description":"Open a rubric to see its scoring rows. Each row names what it looks at, a label, a weight, and a match rule. The match rule is where you say what counts as a fit for that row. The next steps walk through the kinds of rule you can set.","side":"top"}},{"element":"app-data-table","popover":{"title":"Match rule 1 — a keyword list","description":"Open a rubric to try this. A short list of words — aerospace, defense, machining — is a loose keyword search that ignores capitalization. It looks for any of those words in the lead's company name, the source it came from, and its email, and — if the lead is tied to a company account — that company's industry, state, size, and name. Find any word anywhere, and the row counts as a fit and adds its weight. Use this to reward leads that smell like your ideal customer even before the account is fully filled in.","side":"top"}},{"element":"app-data-table","popover":{"title":"Match rule 2 — target industries or states","description":"Open a rubric to try this. Instead of a loose keyword search, you can name the exact industries you serve (say Aerospace and Defense) or the exact states you sell into (say CA, WA, TX). A lead fits when its company's industry — or its state — is one you listed. Reach for this when you want a precise fit on one fact rather than a broad keyword sweep.","side":"top"}},{"element":"app-data-table","popover":{"title":"Match rule 3 — a company-size range","description":"Open a rubric to try this. Set a size range — for example, companies with 50 to 500 employees — and a lead fits when its company's size falls inside that band. This is how you reward the right-sized prospects and steer past the too-small or too-large ones. A lead whose company size isn't known yet simply doesn't fit this row.","side":"top"}},{"element":"[data-testid='icp-rubric-save-btn']","popover":{"title":"Tune, save, wait for the run","description":"Give positive weights to the rows you want to reward and negative weights to the ones you want to penalize. Save the rubric. The change takes effect on the next nightly run, which re-scores every active lead and re-orders the work list.","side":"left"}}]}"""
        });

        // ── Entity Completeness Requirements Admin (Article) ──────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Entity Completeness Requirements",
            Slug = "entity-completeness-overview",
            Summary = "Set the rules that decide when a Vendor, Part, or Customer record has enough information to act on: what one requirement is, how to describe what must be filled in, the short label and the fuller explanation a user sees, and how the completeness indicator lists what's still missing.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/admin/entity-completeness"]""",
            Tags = """["lead-scoring","entity-completeness","records","sales"]""",
            ContentJson = """{"body":"## Entity Completeness Requirements\n\nAdmin → Entity Completeness lets you define what it means for a record to be **complete enough to act on**. Each row answers one question: *\"before we use this vendor, part, or customer for this kind of work, what has to be filled in?\"* The completeness indicator on Vendor, Part, and Customer detail screens reads these rows and lists exactly what's still missing — so a rep opening a customer sees, at a glance, that it still needs a tax ID and a billing address before the order can go out.\n\nThis list ships **empty** on purpose — the information a business needs on a record depends on which parts of the app it uses, so you write the rules that fit your shop rather than fighting a canned set that doesn't.\n\n### What one requirement is\n\nClick **New Requirement** to open the dialog. A requirement is made of:\n\n- **Record type** (required) — which record this applies to: **Vendor**, **Part**, or **Customer**.\n- **Where it applies** (required) — the part of the app this requirement is tied to, chosen from a list (for example the vendor screens, or purchase orders). The requirement only comes into play when your shop uses that part of the app.\n- **A short name for the check** (required) — a stable name for *this one requirement* on that record type, such as tax ID, payment terms, or billing address. Giving each check its own name is what lets a single record type carry several separate requirements that each show up as their own line in the missing list.\n- **What must be true** (required) — the actual rule: which piece of information has to be filled in, or set to a certain value, before the check passes (spelled out below).\n- **Label shown to the user** (required) — the short wording that appears on the record, like 'Tax ID'.\n- **The fuller explanation** (required) — the longer note a user sees when they want to know why it matters, like 'Vendor needs a federal tax ID before it can go on a purchase order'.\n- **Order** — where this check sits in the list, relative to the other checks on the same record type.\n\nBecause the record type, where-it-applies, and short name are **unique as a set**, you add one requirement per thing that must be true — rather than lumping several checks into one — so each shows up as its own line the user can tick off.\n\n### Describing what must be true\n\nEach requirement describes one condition on the record. In plain terms, the kinds of condition you can set are:\n\n- **A field is filled in** — the record has a value for something, like a tax ID or a phone number.\n- **A field equals a specific value** — a setting is exactly what you require, like credit terms set to Net 30.\n- **A number clears a threshold** — a numeric field is above (or below) a cutoff, like a lead time greater than zero.\n- **At least one related item exists** — the record has something attached, like at least one address or one contact.\n- **Several of these at once** — combine conditions when a record needs more than one thing to be true (a vendor that needs *both* a tax ID *and* an address).\n\nA common example — a vendor doesn't count as ready until it has **both** a tax ID **and** at least one address on file. You'd set that up as the combined condition: a tax-ID check and a has-an-address check that both have to pass.\n\nIf a rule is entered incorrectly, the record simply shows that requirement as not-yet-met — the completeness indicator keeps working and never breaks. So you'll see the effect of a bad rule on the record and can fix it.\n\n### The label and the explanation\n\nEvery requirement carries the two pieces of wording the user reads: the **short label** on the record and the **fuller explanation** they see when they look closer. Because the app runs in both English and Spanish, each piece of wording needs both languages filled in. If a label is missing its wording, the record shows a placeholder instead of real words — that's your cue the wording still needs to be added. Keep your naming consistent with the checks already in the list so everything reads cleanly together.\n\n### How the record uses all this\n\nWhen a user opens a Vendor, Part, or Customer, the app takes every requirement that applies to that record type (and to the parts of the app your shop actually uses), checks the record against each one, and lists the ones that don't yet pass as the record's missing items — each with its short label, and the fuller explanation on closer look, in the order you set. Requirements the record already satisfies stay quiet. This is also the groundwork for firmer guard rails later, like not letting a vendor onto a purchase order until its required fields are filled in.\n\n### Filtering and editing\n\nThe page toolbar filters the list by record type and by where-it-applies so you can manage a large set of rules. Edit a row with the pencil icon; delete with the trash icon (you'll confirm first). A change you make takes effect the next time someone opens the affected record — there's no overnight wait here.","sections":[]}"""
        });

        // ── Authoring a Completeness Requirement (Walkthrough) ────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Authoring a Completeness Requirement",
            Slug = "entity-completeness-walkthrough",
            Summary = "A guided tour of the Entity Completeness page: filtering the list of rules, opening the New Requirement form, and setting the record type, where the rule applies, a short name for the check, what must be true, and the wording the user reads.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 5,
            AppRoutes = """["/admin/entity-completeness"]""",
            Tags = """["lead-scoring","entity-completeness","walkthrough","sales"]""",
            ContentJson = """{"appRoute":"/admin/entity-completeness","startButtonLabel":"Tour Entity Completeness","steps":[{"element":"app-toolbar","popover":{"title":"Entity Completeness","description":"This page is where you set the rules for when a vendor, part, or customer record has enough information to act on. The list starts empty — you add the checks your shop needs. The completeness indicator on each record reads these checks and shows what's still missing.","side":"bottom"}},{"element":"app-select","popover":{"title":"Filter by record type","description":"Pick from this menu to narrow the list to vendor, part, or customer checks (or all of them). As your set of rules grows, this is how you find the checks for the record type you're working on.","side":"bottom"}},{"element":"app-input","popover":{"title":"Filter by where it applies","description":"Narrow the list to the checks tied to one part of the app. Each check is tied to a part of the app — it only comes into play when your shop uses that part.","side":"bottom"}},{"element":"[data-testid='ecr-new-btn']","popover":{"title":"New Requirement","description":"Open the form to add a check. You'll pick the record type, where it applies, a short name for the check, what has to be true, the wording the user reads, and where it sits in the list.","side":"left"}},{"element":"app-data-table","popover":{"title":"The requirements list","description":"Each row is one check. The record type, where-it-applies, and short name are unique as a set, so you add several checks — one per thing that must be true — and each shows up on its own line in the record's missing list. The two wording columns hold the label and the explanation the user reads.","side":"top"}},{"element":"app-data-table","popover":{"title":"What must be true","description":"Each check describes one condition on the record: a field is filled in, a field equals a certain value, a number clears a threshold, or a related item exists — like at least one address. You can also combine conditions when a record needs more than one thing at once. A rule entered wrong simply shows as not-yet-met on the record, so you can spot it and fix it — the indicator never breaks.","side":"top"}},{"element":"[data-testid='ecr-new-btn']","popover":{"title":"Don't forget the wording","description":"Each check carries the short label and the fuller explanation the user reads, and because the app runs in English and Spanish, each needs both languages. If the wording is missing, a placeholder shows on the record instead of real words — that's your cue to fill it in. Keep the naming consistent with the checks already in the list so everything reads cleanly.","side":"left"}}]}"""
        });

        // ── Lead Scoring Admin Field Reference (QuickRef) ─────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Lead Scoring Admin Field Reference",
            Slug = "lead-scoring-field-reference",
            Summary = "Quick reference for the three lead-scoring screens: Lead Source fields and how the Quality Score is figured, ICP rubric and dimension fields and the kinds of match rule, and the record-completeness fields with the kinds of check you can set.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 6,
            AppRoutes = """["/admin/lead-sources","/admin/icp-rubrics","/admin/entity-completeness"]""",
            Tags = """["lead-scoring","reference","admin"]""",
            ContentJson = """{"title":"Lead Scoring Admin Field Reference","groups":[{"heading":"Lead Sources — Fields","items":[{"label":"Name","value":"Required. The label people read. Editable any time."},{"label":"Code","value":"Required, set when you create the source, and can't be changed afterward (it's locked when you edit). It's the stable id that imports, forms, and referral links point to. Letters, digits, hyphens, and underscores only."},{"label":"Description","value":"Optional note describing the source (up to 500 characters)."},{"label":"Quality Score","value":"0–100, read-only. Worked out automatically each night from how the source's leads turn out — you never type it. Colored green at 70+, amber 40–69, red under 40."},{"label":"Active","value":"On/off switch (edit only). Off = hidden from new intake but still tied to its past leads."},{"label":"Leads","value":"How many leads are tied to this source. This is what the delete guard checks."},{"label":"Created","value":"The date it was created, shown as MM/dd/yyyy."}]},{"heading":"Lead Sources — Quality Score math","items":[{"label":"Starting value","value":"Every source starts at 50 (neutral)."},{"label":"+5 each","value":"A lead that turned into a customer (the strongest plus)."},{"label":"+2 each","value":"A lead that had a real back-and-forth conversation."},{"label":"−5 each","value":"A lead marked bad data or do-not-contact."},{"label":"−2 each","value":"A lead marked lost."},{"label":"Window","value":"Only leads from about the last 180 days count — that's what keeps the score current."},{"label":"Clamp","value":"The final score is kept within 0–100, and the time of each nightly run is recorded."}]},{"heading":"Lead Sources — Deactivate vs Delete","items":[{"label":"Deactivate","value":"Turn Active off. Use this whenever the source has any leads. Keeps its history and its score."},{"label":"Delete","value":"Trash icon. Blocked with an error if any leads are tied to it. Only for sources created by mistake and never used."}]},{"heading":"ICP Rubric — Header fields","items":[{"label":"Name","value":"Required. Names the rubric (up to 100 characters)."},{"label":"Description","value":"Optional reminder of who the rubric is aimed at (up to 500)."},{"label":"Active","value":"Whether the rubric is in play."},{"label":"Default","value":"Whether this is the rubric the nightly scoring uses. Only one can be the default — pick a new one and the old one is unmarked for you."},{"label":"Dimensions count","value":"Shown in the list; tells you whether the rubric can actually score anything."}]},{"heading":"ICP Dimension — Row fields","items":[{"label":"What it looks at","value":"Required. The fact about the lead or its company this row checks — the industry, the headcount, the state, the company name, or the source it came from."},{"label":"Label","value":"Optional plain description of what the row is looking for."},{"label":"Match rule","value":"What counts as a fit for this row (kinds below). No rule set = no fit."},{"label":"Weight","value":"Required whole number. Positive rewards a fit; negative penalizes a poor fit. Only positive weights count toward the top score."}]},{"heading":"ICP Match rule — Kinds","items":[{"label":"A keyword list","value":"Words like aerospace, defense. A loose search that ignores capitalization, run against the lead's company name, its source, and its email, and its company's industry, state, size, and name. Any word found anywhere is a fit."},{"label":"Target industries","value":"Name the exact industries you serve. A lead fits when its company's industry is one you listed."},{"label":"Target states","value":"Name the exact states you sell into. A lead fits when its company's state is one you listed."},{"label":"A size range","value":"Set a low and high headcount. A lead fits when its company's size falls in that band."},{"label":"Nothing set","value":"A row with no match rule, or a company whose detail isn't known yet, simply doesn't fit — never an error."}]},{"heading":"ICP — Scoring math","items":[{"label":"Per lead","value":"Add up the weight of every row the lead fits."},{"label":"Normalize","value":"Divide that total by the sum of the positive weights, multiply by 100, round, and keep it within 0–100."},{"label":"Saved as","value":"The lead's fit score, written by the nightly run, for leads that aren't already won or lost."},{"label":"Used by","value":"The sales work list, which puts the best-fit leads first."},{"label":"When nothing scores","value":"No active default rubric, the default has no rows, or no positive weight → the nightly run is skipped and no scores change."}]},{"heading":"Entity Completeness — Requirement fields","items":[{"label":"Record type","value":"Required. Vendor, part, or customer."},{"label":"Where it applies","value":"Required. The part of the app this check is tied to (for example the vendor screens, or purchase orders). It only comes into play when your shop uses that part."},{"label":"Short name for the check","value":"Required. A stable name for this one check on that record type. Unique as a set. For example, tax ID or payment terms."},{"label":"What must be true","value":"Required. The condition the record has to meet (kinds below)."},{"label":"Label shown to the user","value":"Required. The short wording that appears on the record, like 'Tax ID'."},{"label":"The fuller explanation","value":"Required. The longer note the user sees on closer look — why it matters and what to fill in."},{"label":"Order","value":"Where it sits in the list, among the other checks on the same record type."}]},{"heading":"What must be true — Kinds of check","items":[{"label":"A field is filled in","value":"The record has a value for something, like a tax ID or a phone number."},{"label":"A field equals a value","value":"A setting is exactly what you require, like credit terms set to Net 30."},{"label":"A number clears a threshold","value":"A numeric field is above (or below) a cutoff, like a lead time greater than zero."},{"label":"At least one item exists","value":"The record has something attached, like at least one address or one contact."},{"label":"A related list has enough","value":"A related list has at least (or at most) a number you set, like two or more contacts."},{"label":"Several at once","value":"Combine conditions when a record needs more than one thing to be true — a vendor with both a tax ID and an address."},{"label":"Plain wording","value":"Name each check the way a rep would say it; the app matches it to the right piece of the record."},{"label":"Safe by default","value":"A check entered wrong simply shows as not-yet-met on the record. It never breaks the indicator."}]},{"heading":"Label and explanation","items":[{"label":"Both languages","value":"The label and the explanation are wording the user reads, and each needs an English and a Spanish version, kept in step."},{"label":"Missing wording","value":"If the wording hasn't been filled in, a placeholder shows on the record instead of real words — your cue to add it."}]},{"heading":"Who works on each screen","items":[{"label":"Lead Sources","value":"The Lead Sources list. Sales managers set them up; the whole sales team reads the Quality Scores."},{"label":"ICP Rubrics","value":"The rubrics and their scoring rows. Owned by sales managers; the fit scores drive every rep's work list."},{"label":"Entity Completeness","value":"The record-completeness checks. Set up by an administrator for the whole shop."}]}]}"""
        });

        // ── Lead Scoring Admin Knowledge Check (Quiz) ─────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Lead Scoring Knowledge Check",
            Slug = "lead-scoring-quiz",
            Summary = "Test your understanding of Lead Sources, ICP rubrics and weighted dimensions, the kinds of match rule, and record-completeness checks.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 7,
            AppRoutes = """["/admin/lead-sources","/admin/icp-rubrics","/admin/entity-completeness"]""",
            Tags = """["lead-scoring","quiz","admin"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ls1","text":"Why can't you change a Lead Source's Code after it's created?","options":[{"id":"a","text":"The Code is the stable natural key that imports, web forms, and referrer URLs bind to — changing it would silently break that attribution","isCorrect":true},{"id":"b","text":"The Code is encrypted and the system has no way to decrypt it"},{"id":"c","text":"Codes are reused across installs and must stay globally unique"},{"id":"d","text":"It can be changed — the field is just hidden by default"}],"explanation":"The Code is the immutable natural key. Bulk-import pipelines map columns to a source Code, and web forms / referrer URLs carry it; historical leads point at it. If it could change, every binding would break. The edit dialog disables the Code field for exactly this reason. Choose it carefully at create time."},{"id":"ls2","text":"Where does a Lead Source's Quality Score come from?","options":[{"id":"a","text":"An admin types it into the source's edit dialog"},{"id":"b","text":"It is worked out automatically each night from how that source's leads turn out","isCorrect":true},{"id":"c","text":"It is pulled from the list provider's API"},{"id":"d","text":"It is the simple count of leads attributed to the source"}],"explanation":"Quality Score is read-only and computed by a nightly job. Every source starts at 50; converted leads add points, engaged leads add fewer, bad-data/suppressed leads subtract, and lost leads subtract a little. Only leads from roughly the last 180 days count, which makes the score 'rolling'. It is never typed by hand."},{"id":"ls3","text":"You try to delete a Lead Source that has 40 leads attributed to it. What happens, and what should you do instead?","options":[{"id":"a","text":"It deletes and the 40 leads lose their source — that's expected"},{"id":"b","text":"The server blocks the delete; you should deactivate the source instead so historical attribution survives","isCorrect":true},{"id":"c","text":"It deletes and the 40 leads are reassigned to the default source"},{"id":"d","text":"Nothing happens — sources can never be deleted"}],"explanation":"Delete is blocked with an error when leads are linked, as a guard rail. The right action is to set the Active toggle off (deactivate): the source disappears from new-intake choices but stays attached to its historical leads, preserving attribution and the Quality Score. Only never-used mistake sources can be hard-deleted."},{"id":"ls4","text":"Which rubric does the nightly ICP scoring job actually use?","options":[{"id":"a","text":"All Active rubrics, averaging the scores together"},{"id":"b","text":"The single rubric that is both Active and Default","isCorrect":true},{"id":"c","text":"The most recently edited rubric"},{"id":"d","text":"Whichever rubric has the most dimensions"}],"explanation":"The job uses exactly one rubric: the one flagged both Active and Default. The server enforces a single default — marking a new rubric default automatically un-defaults the previous one. If no rubric is Active+Default (or it has no dimensions / no positive weight), the job skips and writes no scores."},{"id":"ls5","text":"You set an ICP dimension to match a simple list of words like 'aerospace' and 'defense'. How does a lead count as a match for that dimension?","options":[{"id":"a","text":"The lead's industry field must be typed exactly as 'aerospace' or 'defense', with nothing else accepted"},{"id":"b","text":"If any of those words appears anywhere in the lead's company name, source, email, or its linked account's industry, state, size, or name (ignoring capitalization), the dimension matches","isCorrect":true},{"id":"c","text":"Every word in the list has to appear on the lead before it counts as a match"},{"id":"d","text":"A plain word list can't be used for matching — you always have to pick a single field"}],"explanation":"A simple word list is a loose, case-insensitive 'contains' search. The scoring run looks for any of those words anywhere across the lead's company name, source, email, and — when the lead is tied to an account — that account's industry, state, size, and name. Finding just one word in any one of those places is enough for the dimension to match and add its weight. If instead you need a precise match on one fact — say the company's industry exactly — you use the target-industries or target-states rule instead of a keyword list."},{"id":"ls6","text":"How is a lead's final 0–100 fit score figured from the dimensions?","options":[{"id":"a","text":"It's the count of dimensions the lead fit"},{"id":"b","text":"Add up the weights of the dimensions the lead fits, divide by the sum of all the positive weights, multiply by 100, and keep it within 0–100","isCorrect":true},{"id":"c","text":"It's the single highest weight among the dimensions the lead fits"},{"id":"d","text":"Each dimension is scored 0–100 separately and they're averaged"}],"explanation":"The scoring adds the weight of every dimension the lead fits, divides by the best a lead could score (the sum of the positive weights), scales to 100, and keeps it within 0–100. Because the top of the scale grows with the weights, only the RELATIVE weights matter — a dimension worth twice as much as another is what moves the needle. Negative weights can penalize a poor fit and push a lead toward 0."},{"id":"ls7","text":"After you edit the default rubric's dimension weights, when do lead scores reflect the change?","options":[{"id":"a","text":"Immediately — scores recompute the moment you save"},{"id":"b","text":"On the next nightly run, which re-scores every active lead and re-orders the work list","isCorrect":true},{"id":"c","text":"Only when a rep opens each lead"},{"id":"d","text":"Never — existing scores are frozen once set"}],"explanation":"Scoring isn't live. The fit score you see on a lead is the result of the last overnight run. Editing a rubric today means the new weights take effect on the next run, which re-scores every active lead (skipping ones already won or lost) and re-orders the work list. So expect a change to show up the following morning, not the moment you save."},{"id":"ls8","text":"In the Entity Completeness screen, what is the short name you give each check for?","options":[{"id":"a","text":"It's an internal record number you can't edit"},{"id":"b","text":"A stable name for one specific check on a record type, so a record type can carry several separate checks that each show up on their own line","isCorrect":true},{"id":"c","text":"It points at the lead source the check came from"},{"id":"d","text":"It's the wording shown to the user on the record"}],"explanation":"The record type, where-it-applies, and short name are unique as a set. The short name (like 'tax ID' or 'payment terms') lets one record type carry several separate checks, each surfacing as its own line in the record's missing list. You add one check per thing that must be true rather than lumping several into one."},{"id":"ls9","text":"You want a vendor record to count as complete only once it has both a tax ID and at least one address on file. In the Entity Completeness admin, how do you set that up?","options":[{"id":"a","text":"You add a completeness requirement for the tax ID and another for having an address, so each shows up as its own item a user can check off","isCorrect":true},{"id":"b","text":"You mark the tax ID and address fields as favorites on the vendor screen"},{"id":"c","text":"You raise the vendor's quality score until the missing pieces disappear on their own"},{"id":"d","text":"Completeness is fixed by the system and can't be tailored to a vendor's needs"}],"explanation":"The Entity Completeness admin is where you author what 'complete enough to use' means for a record. You add one requirement per thing that must be true — here, a tax-ID requirement and a has-an-address requirement — each tied to the vendor record type and the feature it supports. Keeping them as separate requirements means each one appears on its own line so a user can see and fix them individually, rather than lumping several checks together."},{"id":"ls10","text":"A vendor record doesn't yet satisfy one of its completeness requirements. What does the user see happen to that record?","options":[{"id":"a","text":"The record is deleted until the missing information is supplied"},{"id":"b","text":"The record is marked as incomplete and the unmet requirement shows up in its list of what's still missing","isCorrect":true},{"id":"c","text":"The user is locked out of the record and can't open it at all"},{"id":"d","text":"Nothing shows at all, so there's no way to tell the record is missing anything"}],"explanation":"An unmet requirement doesn't delete the record or hard-block the user. Instead the record is flagged as incomplete, and that requirement appears in the record's missing list — the running tally of what still needs filling in. The user can keep working with the record and simply see, at a glance, exactly which pieces are outstanding so they know what to supply next."},{"id":"ls11","text":"A user opens a customer record and sees the completeness indicator listing 'Tax ID' and 'Billing address'. What is it telling them, and what should they do?","options":[{"id":"a","text":"Those are the pieces of information still missing from the record; the user should fill them in to make the record complete","isCorrect":true},{"id":"b","text":"Those are fields the user is not allowed to view, so they should ignore them"},{"id":"c","text":"Those are recent changes another user made, so no action is needed"},{"id":"d","text":"Those are optional suggestions that never affect whether the record can be used"}],"explanation":"The completeness indicator lists exactly the required pieces of information that this record is still missing, each shown with a short, readable label and a fuller explanation when you hover. It's a to-do list for making the record usable: the user acts on it by supplying each listed item, and as they do, those entries drop off the list until the record reads as complete."},{"id":"ls12","text":"Why does the Entity Completeness list start empty?","options":[{"id":"a","text":"It's a bug — it should have default checks"},{"id":"b","text":"The information a record needs depends on which parts of the app a shop uses, so you set up the checks that fit rather than fighting a canned set","isCorrect":true},{"id":"c","text":"Completeness rules are imported automatically from the accounting system"},{"id":"d","text":"The checks appear only once the first vendor is created"}],"explanation":"By design, the list is empty on a fresh install. Because a completeness check only matters for the parts of the app a shop actually uses, and every shop uses a different mix, a one-size-fits-all set would be wrong for most. You add exactly the checks your shop's work calls for."}]}"""
        });

        // ── Lead Scoring — Tips for Sales Managers (Reference) ────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Lead Scoring — Tips for Sales Managers",
            Slug = "lead-scoring-reference",
            Summary = "Deeper tips for the sales manager tuning lead scoring: building match rules that actually reward your ideal customer, why scores update overnight and how to read a lagging source, who owns each screen, and keeping record-completeness checks clean.",
            ContentType = TrainingContentType.Reference,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 90,
            AppRoutes = """["/admin/icp-rubrics"]""",
            Tags = """["lead-scoring","tips","sales"]""",
            ContentJson = """{"body":"## Building match rules that reward the right leads\n\nEach dimension's match rule is where a rubric earns its keep. A few patterns worth knowing once you've mastered the basics:\n\n- **Reach for a keyword list when the lead is still thin.** Early in a lead's life you often have little more than a company name and where it came from. A loose keyword list — aerospace, defense, machining — searches the company name, the source, and the email, so it can reward a promising lead before anyone has filled in its full company profile. It ignores capitalization and matches on any word, anywhere.\n- **Reach for exact industries or states when you want precision.** Once a lead is tied to a company with a known industry and location, naming the exact industries you serve, or the exact states you sell into, is sharper than a keyword sweep. A lead fits only when the company's industry — or its state — is one you listed. That avoids a false fit from the word 'defense' turning up in an email signature.\n- **Use a size range to steer past the wrong-sized shops.** A 50-to-500-employee band rewards the prospects you can actually serve and quietly passes over the one-person shops and the giant primes you'll never win.\n- **One rule per dimension; split to require several things.** A single dimension matches on *any* of its criteria — so if you list both industries and a size range on one row, a lead that hits *either* one fits. When you truly need *both* to be true, make them two dimensions with their own weights. That also lets you weight 'right industry' and 'right size' differently, which is usually what you want.\n- **A rule only fires on what's known.** The exact-industry, exact-state, and size-range rules all lean on the lead's linked company. A lead with no company attached can still be rewarded by a keyword list, but it can't match those company-specific rules — worth remembering when a promising lead scores lower than you'd expect. The fix is usually to attach or fill in the company, not to change the rubric.\n\n## Why scores update overnight — and reading a lagging source\n\nLead scoring runs once a night, not the instant you save. That's deliberate: scoring every lead against every rubric dimension is heavy work, so it happens in the quiet hours.\n\nWhat that means day to day:\n\n- **The fit score on a lead is last night's answer.** Edit a rubric this afternoon and the new weights show up tomorrow morning, after the overnight run re-scores every active lead (it skips leads already won or lost) and re-orders the work list.\n- **A brand-new source sits at the neutral 50 for a while.** A source's Quality Score only moves once its leads start turning into wins, engaged conversations, or dead ends — and only leads from roughly the last six months count, which is what keeps the score current instead of dragging around old history. A fresh source with nothing in that window simply stays at 50 until its leads accumulate outcomes.\n- **A score that never seems to update is worth a look.** If a source's score is stuck when you'd expect it to move, the leads may be older than the six-month window, or the source may be inactive (inactive sources aren't re-scored at all). Reactivate it, or check the leads' dates, before assuming the number is wrong.\n\n## Who owns each screen\n\nThe three screens are set up by different people, which is worth knowing when something needs changing:\n\n- **Lead Sources** — a sales manager keeps the catalog current: adding new campaigns and shows, deactivating spent ones. The whole sales team reads the Quality Scores to judge where the good leads come from.\n- **ICP Rubrics** — a sales manager owns the rubric and its weights, because it encodes the team's judgment about what a good customer looks like. Every rep feels the result: the rubric decides the order of their work list.\n- **Entity Completeness** — the record-completeness checks are set up by an administrator for the whole shop, since they touch vendors, parts, and customers across the business, not just sales. If a customer record is asking for a field you think it shouldn't, that's a conversation with your admin.\n\n## Keeping record-completeness checks clean\n\nA few habits keep the completeness checks useful rather than noisy:\n\n- **One check per thing that must be true.** If a vendor needs both a tax ID and an address, make two checks, not one combined rule. Each then shows up as its own line the user can tick off, so they can see exactly what's left rather than a single all-or-nothing flag.\n- **Only add checks for parts of the app you actually use.** A check tied to purchase orders only comes into play for shops that raise purchase orders. Checks tied to features you don't use stay quiet and won't clutter a record with irrelevant asks.\n- **Fill in the wording in both languages.** Every check carries a short label and a fuller explanation the user reads, and the app runs in English and Spanish. If either language is missing its wording, the record shows a placeholder instead of real words — an easy tell that a check still needs finishing. Keep the naming in step with the checks already in the list so the missing-items list reads cleanly.\n- **A wrong check is safe, not silent.** If a check is set up incorrectly, the record simply lists it as not-yet-met rather than passing it by mistake. So a mis-set rule shows itself on the record — you'll notice it and can fix it — instead of quietly letting an incomplete record look ready.","sections":[]}"""
        });

        Log.Information("Seeded Lead Scoring training modules (sales-role centered)");
    }
